const allPosts = $('Fetch Due Posts').all();
const individualPost = allPosts.find(p => p.json && p.json.channel === 'individual');
if (!individualPost) {
  return [];
}
const memberUrn = $input.first().json.sub;
if (!memberUrn) {
  throw new Error('Could not resolve LinkedIn member URN from userinfo response: ' + JSON.stringify($input.first().json));
}
return [{ json: { memberUrn, content: individualPost.json.content, post_id: individualPost.json.id } }];

const allPosts = $('Fetch Due Posts').all();
const databizPost = allPosts.find(p => p.json && p.json.channel === 'databiz');
if (!databizPost) {
  return [];
}

function extractAccounts(data) {
  if (Array.isArray(data)) return data;
  if (data && typeof data === 'object') {
    if (data.platform) return [data];
    for (const key of ['data', 'accounts', 'results', 'items']) {
      if (Array.isArray(data[key])) return data[key];
    }
    for (const value of Object.values(data)) {
      if (Array.isArray(value)) return value;
    }
  }
  return [];
}

const rawBody = $input.first().json;
const allAccounts = extractAccounts(rawBody);
const linkedinAccounts = allAccounts.filter(acc => acc.platform && acc.platform.toLowerCase() === 'linkedin');

if (linkedinAccounts.length === 0) {
  throw new Error('No LinkedIn accounts found in Zernio. Raw response: ' + JSON.stringify(rawBody));
}

const targetAccount = linkedinAccounts.find(acc =>
  acc.metadata && (acc.metadata.accountType === 'organization' || acc.metadata.accountType === 'company')
) || linkedinAccounts[0];

const accountId = targetAccount.accountId || targetAccount.id || targetAccount._id || targetAccount.account_id;
if (!accountId) {
  throw new Error('Resolved LinkedIn account has no ID. Account: ' + JSON.stringify(targetAccount));
}

return [{ json: { accountId, content: databizPost.json.content, post_id: databizPost.json.id } }];
